import 'package:flutter/material.dart'; import 'package:flutter_test/flutter_test.dart'; void main() { group('DeviceCard', () { testWidgets('shows Connect button when online', (tester) async { await tester.pumpWidget(const MaterialApp(home: Scaffold(body: Row(children: [Text('Device'), Spacer(), ElevatedButton(onPressed: null, child: Text('Connect'))])))); expect(find.text('Connect'), findsOneWidget); }); testWidgets('shows Offline text when not online', (tester) async { await tester.pumpWidget(const MaterialApp(home: Scaffold(body: Text('Offline')))); expect(find.text('Offline'), findsOneWidget); }); }); }